# ---------------------- База данных ----------------------
def init_db():
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    cur.execute('''
        CREATE TABLE IF NOT EXISTS users (
            user_id INTEGER PRIMARY KEY,
            username TEXT,
            completed_scenarios TEXT DEFAULT '[]',
            quiz_score INTEGER DEFAULT 0,
            terms_seen INTEGER DEFAULT 0
        )
    ''')
    conn.commit()
    conn.close()

def get_user(user_id):
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    cur.execute("SELECT completed_scenarios, quiz_score, terms_seen FROM users WHERE user_id = ?", (user_id,))
    row = cur.fetchone()
    conn.close()
    if row:
        return {"completed": eval(row[0]), "quiz_score": row[1], "terms_seen": row[2]}
    return {"completed": [], "quiz_score": 0, "terms_seen": 0}

def save_user(user_id, username, completed_scenarios=None, quiz_score=None, terms_seen=None):
    conn = sqlite3.connect(DB_PATH)
    cur = conn.cursor()
    cur.execute("SELECT completed_scenarios, quiz_score, terms_seen FROM users WHERE user_id = ?", (user_id,))
    row = cur.fetchone()
    if row:
        current = {"completed": eval(row[0]), "quiz_score": row[1], "terms_seen": row[2]}
        new_completed = completed_scenarios if completed_scenarios is not None else current["completed"]
        new_quiz = quiz_score if quiz_score is not None else current["quiz_score"]
        new_terms = terms_seen if terms_seen is not None else current["terms_seen"]
        cur.execute("UPDATE users SET completed_scenarios = ?, quiz_score = ?, terms_seen = ? WHERE user_id = ?",
                    (str(new_completed), new_quiz, new_terms, user_id))
    else:
        new_completed = completed_scenarios if completed_scenarios is not None else []
        new_quiz = quiz_score if quiz_score is not None else 0
        new_terms = terms_seen if terms_seen is not None else 0
        cur.execute("INSERT INTO users (user_id, username, completed_scenarios, quiz_score, terms_seen) VALUES (?, ?, ?, ?, ?)",
                    (user_id, username, str(new_completed), new_quiz, new_terms))
    conn.commit()
    conn.close()

def add_completed_scenario(user_id, scenario_name):
    data = get_user(user_id)
    completed = data["completed"]
    if scenario_name not in completed:
        completed.append(scenario_name)
        save_user(user_id, None, completed_scenarios=completed)

