# ---------------------- FSM для теста по терминам (6 вопросов) ----------------------
class TermsTest(StatesGroup):
    q1 = State()
    q2 = State()
    q3 = State()
    q4 = State()
    q5 = State()
    q6 = State()

# ---------------------- Тест по терминам (FSM, 6 вопросов) ----------------------
@dp.callback_query(F.data == "terms_test")
async def terms_test_start(callback: CallbackQuery, state: FSMContext):
    await state.set_state(TermsTest.q1)
    await callback.message.answer(
        "🧠 Проверим, насколько ты шаришь за страховой сленг.\n\n"
        "Вопрос 1: Что такое риск?\n"
        "1️⃣ Уже случившаяся беда\n"
        "2️⃣ Вероятность неприятности\n"
        "3️⃣ Выплата денег",
        reply_markup=InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="1", callback_data="tq1_wrong"),
             InlineKeyboardButton(text="2", callback_data="tq1_correct"),
             InlineKeyboardButton(text="3", callback_data="tq1_wrong")]
        ])
    )
    await callback.answer()

@dp.callback_query(F.data == "tq1_correct")
async def tq1_correct(callback: CallbackQuery, state: FSMContext):
    await state.update_data(score=1)
    await callback.message.answer(
        "✅ Верно! Риск — это когда ты еще не влетел, но вероятность есть. "
        "Например, катаешься без наколенников — риск разбить коленку."
    )
    await state.set_state(TermsTest.q2)
    await callback.message.answer(
        "Вопрос 2: Что такое страховой случай?\n"
        "1️⃣ Событие, когда страховая должна заплатить\n"
        "2️⃣ Деньги, которые ты платишь за страховку\n"
        "3️⃣ Документ, где всё написано",
        reply_markup=InlineKeyboardMarkup(inline_keyboard=[
            [InlineKeyboardButton(text="1", callback_data="tq2_correct"),
             InlineKeyboardButton(text="2", callback_data="tq2_wrong"),
             InlineKeyboardButton(text="3", callback_data="tq2_wrong")]
        ])
    )
    await callback.answer()

