@dp.callback_query(F.data == "tq6_correct")
async def tq6_correct(callback: CallbackQuery, state: FSMContext):
    data = await state.get_data()
    score = data.get("score", 0) + 1
    await state.clear()

    if score <= 2:
        result = "😅 Страховой нуб, термины не твоё. Загляни в глоссарий, там всё разжёвано по-братски."
    elif score <= 4:
        result = "👍 Неплохо! Ты уже шаришь, но пару терминов подзабыл. Пройди глоссарий ещё раз и станешь профи."
    else:
        result = "🔥 Ого, ты страховой нёрд! Респект, теперь ты можешь объяснить пацанам, что к чему. Гоу проходить кейсы!"

    await callback.message.answer(
        f"🎉 Твой результат: {score} из 6 правильных ответов.\n\n"
        f"{result}\n\n"
        "Можешь вернуться в главное меню.",
        reply_markup=main_menu_kb
    )
    await callback.answer()

