@dp.message(Command("start"))
async def cmd_start(message: Message):
    user_id = message.from_user.id
    username = message.from_user.username or "no_username"
    save_user(user_id, username)
    await message.answer(
        "**Привет! Я — Страховой Гид.** 🤙\n\n"
        "Хочешь иметь реально нишевое хобби? Welcome!\n"
        "Мы сделали этого бота, чтобы помочь зумерам разобраться в страховке без скучных лекций.\n"
        "Тут ты узнаешь, как не потерять бабки на ремонте телефона, отмене концерта, краже скинов и других жизненных кринжах.\n\n"
        "**Как это работает:**\n"
        "— Сначала загляни в **Глоссарий** — прошаришь за лор страхования.\n"
        "— Потом проходи **Кейсы** — реальные ситуации, где страховка может спасти.\n"
        "— В конце пройди **Босс-тест**, чтобы проверить себя и получить ачивку!\n\n"
        "Погнали! 🚀",
        reply_markup=main_menu_kb,
        parse_mode="Markdown"
    )

