@dp.callback_query(F.data == "glossary_back")
async def glossary_back(callback: CallbackQuery):
    await show_glossary_menu(callback)

@dp.callback_query(F.data.startswith("gloss_"))
async def glossary_detail(callback: CallbackQuery):
    term = callback.data.split("_")[1]
    item = GLOSSARY.get(term)
    if not item:
        await callback.answer("Неизвестный термин.")
        return

    kb = InlineKeyboardMarkup(inline_keyboard=[
        [InlineKeyboardButton(text="🔙 Все, я устал", callback_data="glossary_terms")]
    ])

    # Пробуем как анимацию (если это гифка)
    try:
        media = InputMediaAnimation(media=item["id"], caption=item["text"], parse_mode="Markdown")
        await callback.message.edit_media(media=media, reply_markup=kb)
    except Exception as e:
        print(f"Ошибка при edit_media (возможно, это не анимация или неверный file_id): {e}")
        # Пробуем как фото
        try:
            media = InputMediaPhoto(media=item["id"], caption=item["text"], parse_mode="Markdown")
            await callback.message.edit_media(media=media, reply_markup=kb)
        except Exception as e2:
            print(f"Ошибка при edit_media (фото): {e2}")
            # Если не получилось заменить, удаляем и шлём новое сообщение
            await callback.message.delete()
            # Пробуем отправить анимацией
            try:
                await callback.message.answer_animation(animation=item["id"], caption=item["text"], reply_markup=kb, parse_mode="Markdown")
            except:
                # Если и анимация не сработала, пробуем фото
                await callback.message.answer_photo(photo=item["id"], caption=item["text"], reply_markup=kb, parse_mode="Markdown")
    await callback.answer()

