# ----- Вопрос 5 (финал) -----
@dp.callback_query(F.data == "boss_q5_correct")
async def boss_q5_correct(callback: CallbackQuery, state: FSMContext):
    data = await state.get_data()
    score = data.get("score", 0) + 1
    user_id = callback.from_user.id
    save_user(user_id, None, quiz_score=score)
    await state.clear()

    if score <= 1:
        level = "😅 Страховой нуб, но ничего, перепроходи кейсы, докачай скилл"
        bonus = None
    elif score <= 3:
        level = "👍 Страховой скилл в прокачке, ты уже не ноль"
        bonus = None
    else:
        level = "🔥 Страховой задрот, уважаю! Забери ачивку и поделись с пацанами"
        bonus = True

    # Отправляем результат
    await callback.message.answer(
        f"🎉 Твой результат: {score} из 5 правильных ответов.\n\n{level}",
        reply_markup=main_menu_kb
    )
    if bonus:
        print("🎁 Бонус активирован!")
        try:
            # Расшифровываем нашу большую строку обратно в байты
            file_bytes = base64.b64decode(PDF_BASE64_STRING)
            # Создаем объект для отправки файла из памяти
            pdf_file = BufferedInputFile(file_bytes, filename="secret_bonus.pdf")
            # Отправляем PDF
            await callback.message.answer_document(
                document=pdf_file,
                caption="🎁 Твой секретный бонус от страхового гида!"
            )
        except Exception as e:
            print(f"Ошибка при отправке бонуса из памяти: {e}")
            await callback.message.answer("Не удалось отправить бонус, но ты всё равно красавчик!")

@dp.callback_query(F.data == "boss_q5_wrong")
async def boss_q5_wrong(callback: CallbackQuery, state: FSMContext):
    data = await state.get_data()
    score = data.get("score", 0)   # без добавления балла
    user_id = callback.from_user.id
    save_user(user_id, None, quiz_score=score)
    await state.clear()

    if score <= 1:
        level = "😅 Страховой нуб, но ничего, перепроходи кейсы, докачай скилл"
    elif score <= 3:
        level = "👍 Страховой скилл в прокачке, ты уже не ноль"
    else:
        level = "🔥 Страховой задрот, уважаю! Забери ачивку и поделись с пацанами"

    await callback.message.answer(
        f"❌ Неа. Правильный ответ: собрать документы и подать заявление. Без пруфов выплату не дадут.\n\n"
        f"🎉 Твой результат: {score} из 5 правильных ответов.\n\n{level}",
        reply_markup=main_menu_kb
    )
    # Бонус не даётся, так как ответ неправильный
    await callback.answer()

